changeSet.sql:
ALTER TABLE exercises DROP CONSTRAINT IF EXISTS chk_exercises_category;
ALTER TABLE exercises
    ADD CONSTRAINT chk_exercises_category
    CHECK (category IN ('strength','bodyweight','timed','cardio','amrap','mobility','plyometric','skill'));

